@tailwind base;
@tailwind components;
@tailwind utilities;

/* ── BlindBounty Design System Tokens ──────────────────────────── */

/* Light theme (default) */
:root {
  --bb-bg:         #fafaf9;
  --bb-surface:    #ffffff;
  --bb-surface-2:  #f5f5f4;
  --bb-line:       #d6d3d1;
  --bb-line-2:     #a8a29e;
  --bb-ink:        #09090b;
  --bb-ink-2:      #3f3f46;
  --bb-ink-3:      #71717a;
  --bb-invert:     #09090b;
  --bb-invert-fg:  #fafaf9;
  --bb-cream:      #b8860b;
  --bb-ok:         #047857;
  --bb-warn:       #b45309;
  --bb-err:        #b91c1c;
  --bb-info:       #1d4ed8;
}

/* Dark theme */
html[data-theme="dark"] {
  --bb-bg:         #09090b;
  --bb-surface:    #0d0d0d;
  --bb-surface-2:  #111113;
  --bb-line:       #27272a;
  --bb-line-2:     #3f3f46;
  --bb-ink:        #fafaf9;
  --bb-ink-2:      #d4d4d8;
  --bb-ink-3:      #a1a1aa;
  --bb-invert:     #f5efe0;
  --bb-invert-fg:  #09090b;
  --bb-cream:      #f5efe0;
  --bb-ok:         #10b981;
  --bb-warn:       #f59e0b;
  --bb-err:        #ef4444;
  --bb-info:       #3b82f6;
}

