  .btn-bracket-primary:hover {
    opacity: 0.9;
  }

  /* ── Ghost button ────────────────────────────────────────────── */
  .btn-ghost {
    @apply px-4 py-2 border border-line text-ink-2 text-xs font-mono font-medium tracking-wide transition-colors duration-200;
  }
  .btn-ghost:hover {
    @apply border-line-2 text-ink;
  }

  /* ── Section rule — §N ─ TITLE ───────────────────────────────── */
  .section-rule {
    @apply flex items-center gap-3 text-[11px] font-mono font-semibold uppercase tracking-widest text-ink-3;
  }
  .section-rule .section-num {
    color: var(--bb-cream);
  }
  .section-rule::after {
    content: '';
    @apply flex-1 h-px bg-line;
  }

  /* ── Status chip — uppercase, tiny, semantic colors ──────────── */
  .chip {
    @apply inline-flex items-center gap-1 px-2 py-0.5 text-[9px] font-mono font-semibold uppercase tracking-wider border whitespace-nowrap;
  }
  .chip-ok {
    background: rgba(16, 185, 129, 0.12);
    color: var(--bb-ok);
    border-color: rgba(16, 185, 129, 0.25);
  }
  .chip-err {
    background: rgba(239, 68, 68, 0.12);
    color: var(--bb-err);
    border-color: rgba(239, 68, 68, 0.25);
  }
  .chip-info {
    background: rgba(59, 130, 246, 0.12);
    color: var(--bb-info);
    border-color: rgba(59, 130, 246, 0.25);
  }
  .chip-warn {
    background: rgba(217, 119, 6, 0.12);
    color: var(--bb-warn);
    border-color: rgba(217, 119, 6, 0.25);
  }
  .chip-neutral {
    @apply border-line text-ink-3 bg-transparent;
  }

  /* ── Section label ───────────────────────────────────────────── */
  .section-label {
    @apply text-[11px] uppercase tracking-widest text-ink-3 font-mono font-medium;
  }

  /* ── Display heading — IBM Plex Mono, medium weight ──────────── */
  .heading-display {
    font-family: 'IBM Plex Mono', ui-monospace, monospace;
    @apply font-medium text-ink leading-[1.05];
    letter-spacing: -0.015em;
  }

  /* ── Lifecycle row ───────────────────────────────────────────── */
  .lifecycle-row {
    @apply flex items-center justify-between py-2 text-xs font-mono;
  }
  .lifecycle-dot-active {
    @apply w-2 h-2 bg-cream mr-3 inline-block;
  }
  .lifecycle-dot-pending {
    @apply w-2 h-2 border border-ink-3 mr-3 inline-block;
  }
}

