}

export function findByCapabilities(
  required: AgentCapability[],
  minReputation = 0,
): AgentExecutor[] {
  return Array.from(agents.values()).filter((a) => {
    if (a.reputation < minReputation) return false;
    return required.every((cap) => a.capabilities.includes(cap));
