  capabilities: AgentCapability[];
  status: AgentStatus;
  deployedAt: string;
  storageRef?: string;
  // On-chain identity — generated at deploy time
  walletAddress: string;        // Ethereum address derived from keypair
  publicKey: string;            // Uncompressed secp256k1 pubkey (hex)
