import { randomBytes, createCipheriv, createDecipheriv, createHash, createECDH, hkdfSync } from 'crypto';

/**
 * Encryption utilities for BlindBounty.
 *
 * The backend NEVER decrypts task content or evidence.
 * These utilities exist so the SDK/frontend can:
 *   1. Encrypt blobs with AES-256-GCM before uploading
 *   2. Wrap AES keys with ECIES for key exchange
 *   3. Generate keypairs (ECDH on secp256k1)
 *
 * Flow:
 *   Agent creates task:
 *     - Generate AES key → encrypt instructions → upload to 0G
 *     - ECIES-wrap AES key to agent's own pubkey (self-backup)
 *
 *   Agent assigns worker:
 *     - ECIES-wrap same AES key to worker's pubkey → send wrapped key
 *
 *   Worker submits evidence:
 *     - Generate new AES key → encrypt evidence → upload to 0G
 *     - ECIES-wrap to enclave pubkey (for Sealed Inference)
 *     - ECIES-wrap to agent pubkey (for agent review)
 */

const ALGORITHM = 'aes-256-gcm';
const IV_LENGTH = 12;     // GCM standard
const TAG_LENGTH = 16;    // GCM auth tag
const KEY_LENGTH = 32;    // AES-256
const ECIES_PUBKEY_LENGTH = 65; // uncompressed secp256k1
const ECIES_MIN_BLOB = ECIES_PUBKEY_LENGTH + IV_LENGTH + TAG_LENGTH + 1; // 94 bytes minimum
const AES_MIN_BLOB = IV_LENGTH + TAG_LENGTH + 1; // 29 bytes minimum

// Domain separation string for ECIES key derivation (prevents cross-protocol reuse)
const ECIES_HKDF_INFO = 'BlindBounty-ECIES-v1';

// ── AES-256-GCM (symmetric) ──

/** Encrypt plaintext with AES-256-GCM. Returns iv + tag + ciphertext concatenated. */
export function aesEncrypt(plaintext: Buffer, key: Buffer): Buffer {
  if (key.length !== KEY_LENGTH) {
    throw new Error(`AES key must be exactly ${KEY_LENGTH} bytes, got ${key.length}`);
  }
  const iv = randomBytes(IV_LENGTH);
  const cipher = createCipheriv(ALGORITHM, key, iv, { authTagLength: TAG_LENGTH });
  const encrypted = Buffer.concat([cipher.update(plaintext), cipher.final()]);
  const tag = cipher.getAuthTag();
  // Format: [12 bytes IV][16 bytes tag][ciphertext]
  return Buffer.concat([iv, tag, encrypted]);
}

/** Decrypt AES-256-GCM blob. Input format: [12 IV][16 tag][ciphertext]. */
export function aesDecrypt(blob: Buffer, key: Buffer): Buffer {
  if (key.length !== KEY_LENGTH) {
    throw new Error(`AES key must be exactly ${KEY_LENGTH} bytes, got ${key.length}`);
  }
  if (blob.length < AES_MIN_BLOB) {
    throw new Error(`AES blob too short: need at least ${AES_MIN_BLOB} bytes, got ${blob.length}`);
  }
  const iv = blob.subarray(0, IV_LENGTH);
  const tag = blob.subarray(IV_LENGTH, IV_LENGTH + TAG_LENGTH);
  const ciphertext = blob.subarray(IV_LENGTH + TAG_LENGTH);
  const decipher = createDecipheriv(ALGORITHM, key, iv, { authTagLength: TAG_LENGTH });
  decipher.setAuthTag(tag);
  return Buffer.concat([decipher.update(ciphertext), decipher.final()]);
}

/** Generate a random AES-256 key */
export function generateAesKey(): Buffer {
  return randomBytes(KEY_LENGTH);
}

// ── ECIES (asymmetric key wrapping via ECDH + HKDF + AES) ──

/** Generate a secp256k1 keypair. Returns { privateKey, publicKey } as hex strings. */
export function generateKeyPair(): { privateKey: string; publicKey: string } {
  const ecdh = createECDH('secp256k1');
  ecdh.generateKeys();
  return {
    privateKey: ecdh.getPrivateKey('hex'),
    publicKey: ecdh.getPublicKey('hex', 'uncompressed'),
  };
}

/**
 * ECIES encrypt: wrap data to a recipient's public key.
 *
 * 1. Generate ephemeral keypair
 * 2. ECDH shared secret with recipient's pubkey
 * 3. Derive AES key via HKDF-SHA256 with domain separation
 * 4. AES-256-GCM encrypt the data
 * 5. Return ephemeralPubKey + encrypted blob
 */
export function eciesEncrypt(data: Buffer, recipientPubKeyHex: string): Buffer {
  const ephemeral = createECDH('secp256k1');
  ephemeral.generateKeys();

  const sharedSecret = ephemeral.computeSecret(Buffer.from(recipientPubKeyHex, 'hex'));
  const derivedKey = Buffer.from(hkdfSync('sha256', sharedSecret, '', ECIES_HKDF_INFO, KEY_LENGTH));

  const encrypted = aesEncrypt(data, derivedKey);
  const ephemeralPub = ephemeral.getPublicKey();

  // Format: [65 bytes uncompressed ephemeral pubkey][encrypted blob]
  return Buffer.concat([ephemeralPub, encrypted]);
}

/**
 * ECIES decrypt: unwrap data with recipient's private key.
 *
 * 1. Extract ephemeral pubkey (first 65 bytes)
 * 2. ECDH shared secret with own private key
 * 3. Derive AES key via HKDF-SHA256 with domain separation
 * 4. AES-256-GCM decrypt
 */
export function eciesDecrypt(blob: Buffer, recipientPrivKeyHex: string): Buffer {
  if (blob.length < ECIES_MIN_BLOB) {
    throw new Error(`ECIES blob too short: need at least ${ECIES_MIN_BLOB} bytes, got ${blob.length}`);
  }

  const ephemeralPub = blob.subarray(0, ECIES_PUBKEY_LENGTH);
  const encrypted = blob.subarray(ECIES_PUBKEY_LENGTH);

  const ecdh = createECDH('secp256k1');
  ecdh.setPrivateKey(Buffer.from(recipientPrivKeyHex, 'hex'));

  const sharedSecret = ecdh.computeSecret(ephemeralPub);
  const derivedKey = Buffer.from(hkdfSync('sha256', sharedSecret, '', ECIES_HKDF_INFO, KEY_LENGTH));

  return aesDecrypt(encrypted, derivedKey);
}

/** SHA-256 hash of data, returned as hex string (for on-chain taskHash/evidenceHash) */
export function sha256(data: Buffer): string {
  return createHash('sha256').update(data).digest('hex');
}

/** Generate a random nonce (hex string) */
export function generateNonce(): string {
  return randomBytes(32).toString('hex');
}

import { Indexer, MemData } from '@0gfoundation/0g-ts-sdk';
import { ethers } from 'ethers';
import { createHash, randomBytes } from 'crypto';
import { writeFileSync, readFileSync, mkdirSync, existsSync, unlinkSync } from 'fs';
import { join, resolve } from 'path';
import { tmpdir } from 'os';
import { config } from '../config.js';

/**
 * 0G Storage service — upload/download encrypted blobs.
 *
 * Encryption happens CLIENT-SIDE. This service is "blind":
 * it only sees encrypted bytes and root hashes.
 *
 * Falls back to local file storage when 0G Storage is not configured
 * (OG_STORAGE_INDEXER_RPC is empty). Local fallback is for development
 * only — not production-safe (no replication, no merkle proofs, no dedup).
 */

// ── 0G SDK setup ──

let indexer: InstanceType<typeof Indexer> | null = null;
let signer: ethers.Wallet | null = null;

function is0gConfigured(): boolean {
  return !!(config.ogStorageIndexerRpc && config.ogStoragePrivateKey);
}

function getIndexer(): InstanceType<typeof Indexer> {
  if (!indexer) {
    indexer = new Indexer(config.ogStorageIndexerRpc);
  }
  return indexer;
}

function getSigner(): ethers.Wallet {
  if (!signer) {
    const provider = new ethers.JsonRpcProvider(config.ogRpcUrl, config.ogChainId);
    signer = new ethers.Wallet(config.ogStoragePrivateKey, provider);
  }
  return signer;
}

// ── Local fallback ──

const LOCAL_DIR = resolve(process.cwd(), '.storage');

function ensureLocalDir() {
  if (!existsSync(LOCAL_DIR)) {
    mkdirSync(LOCAL_DIR, { recursive: true });
  }
}

/** Validate path stays inside LOCAL_DIR (prevent traversal) */
function safePath(rootHash: string): string | null {
  const target = resolve(LOCAL_DIR, rootHash);
  if (!target.startsWith(LOCAL_DIR + '/') && target !== LOCAL_DIR) {
    return null;
  }
  return target;
}

// ── Public API ──

/**
 * Upload an encrypted blob to 0G Storage (or local fallback).
 * Returns the root hash (sha256 for local, merkle root for 0G).
 */
export async function upload(data: Buffer): Promise<{ rootHash: string; txHash?: string }> {
  if (!is0gConfigured()) {
    return uploadLocal(data);
  }
  return upload0g(data);
}

/**
 * Download an encrypted blob by root hash.
 * Returns the raw encrypted bytes or null if not found.
 */
export async function download(rootHash: string): Promise<Buffer | null> {
  if (!is0gConfigured()) {
    return downloadLocal(rootHash);
  }
  return download0g(rootHash);
}

// ── 0G Storage implementation ──

async function upload0g(data: Buffer): Promise<{ rootHash: string; txHash?: string }> {
  const idx = getIndexer();
  const sgn = getSigner();

  const memData = new MemData(new Uint8Array(data));

  // Compute merkle tree to get root hash BEFORE upload
  const [tree, treeErr] = await memData.merkleTree();
  if (treeErr !== null || !tree) {
    console.error('0G merkle tree error:', treeErr);
    throw new Error('Storage upload failed: merkle tree computation error');
  }
  const rootHash = tree.rootHash() as string;

  // Upload to 0G Storage network
  // Cast signer to `any` — 0G SDK pins ethers 6.13.1 CJS types,
  // our project uses ethers 6.x ESM. Runtime is identical.
  const [tx, uploadErr] = await idx.upload(memData, config.ogRpcUrl, sgn as any);
  if (uploadErr !== null) {
    console.error('0G upload error:', uploadErr);
    throw new Error('Storage upload failed');
  }

  // Extract txHash from SDK response (shape varies by SDK version)
  let txHash: string | undefined;
  if (typeof tx === 'object' && tx !== null && 'txHash' in tx) {
    txHash = (tx as any).txHash;
  }

  return { rootHash, txHash };
}

async function download0g(rootHash: string): Promise<Buffer | null> {
  const idx = getIndexer();

  // SDK downloads to a file — use a temp file with random suffix to avoid races
  const rand = randomBytes(8).toString('hex');
  const tmpPath = join(tmpdir(), `0g-${rootHash}-${rand}`);

  try {
    const err = await idx.download(rootHash, tmpPath, true);
    if (err !== null) {
      console.error(`0G download error for ${rootHash}:`, err);
      return null;
    }
    return readFileSync(tmpPath);
  } catch (e) {
    console.error(`0G download exception for ${rootHash}:`, e);
    return null;
  } finally {
    try { unlinkSync(tmpPath); } catch { /* ignore cleanup errors */ }
  }
}

// ── Local fallback implementation (development only) ──

async function uploadLocal(data: Buffer): Promise<{ rootHash: string }> {
  ensureLocalDir();
  const rootHash = createHash('sha256').update(data).digest('hex');
  const target = safePath(rootHash);
  if (!target) throw new Error('Invalid hash');
  writeFileSync(target, data);
  return { rootHash };
}

async function downloadLocal(rootHash: string): Promise<Buffer | null> {
  ensureLocalDir();
  const target = safePath(rootHash);
  if (!target) return null;
  if (!existsSync(target)) return null;
  return readFileSync(target);
}

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAccount, useWalletClient } from 'wagmi';
import { ConnectButton } from '@rainbow-me/rainbowkit';
import { SigningKey, hashMessage } from 'ethers';

const PROVIDERS = {
  openai:    { label: 'OpenAI',    models: ['gpt-4o', 'gpt-4o-mini', 'gpt-4-turbo'] },
  anthropic: { label: 'Anthropic', models: ['claude-opus-4-5', 'claude-sonnet-4-5', 'claude-3-haiku-20240307'] },
  groq:      { label: 'Groq',      models: ['llama-3.3-70b-versatile', 'llama3-8b-8192', 'mixtral-8x7b-32768'] },
  gemini:    { label: 'Gemini',    models: ['gemini-2.0-flash', 'gemini-1.5-flash', 'gemini-1.5-pro'] },
} as const;

type Provider = keyof typeof PROVIDERS;

export default function DeployAgent() {
  const { address, isConnected } = useAccount();
  const { data: walletClient } = useWalletClient();
  const navigate = useNavigate();

  const [form, setForm] = useState({
    name: '',
    instructions: '',
    provider: 'openai' as Provider,
    model: 'gpt-4o-mini',
    apiKey: '',
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    setForm(f => ({ ...f, model: PROVIDERS[f.provider].models[0] }));
  }, [form.provider]);

  async function handleDeploy(e: React.FormEvent) {
    e.preventDefault();
    if (!isConnected || !address) { 
      setError('Please connect your wallet first');
      return; 
    }
    setLoading(true);
    setError('');
    try {
      // Derive the owner's real secp256k1 public key by recovering it from a signature
      if (!walletClient) throw new Error('Wallet client not ready');
      const msg = 'BlindBounty: authorize agent deployment';
      const sig = await walletClient.signMessage({ message: msg });
      const publicKeyHex = SigningKey.recoverPublicKey(hashMessage(msg), sig).slice(2); // remove 0x04 prefix? No — keep full uncompressed

      const res = await fetch('/api/v1/agents/deploy', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ 
          ...form, 
          ownerAddress: address,
          ownerPublicKey: publicKeyHex.startsWith('04') ? publicKeyHex : `04${publicKeyHex}`,
        }),
      });
      const json = await res.json();
      if (!json.success) throw new Error(json.error?.message ?? 'Deploy failed');
      navigate('/agents');
    } catch (err: unknown) {
      setError((err as Error).message);
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="max-w-2xl mx-auto px-4 py-10">
      <h1 className="text-2xl font-bold text-white mb-1">Deploy an Agent</h1>
      <p className="text-gray-400 mb-8 text-sm">
        Your agent will pick up open tasks, call your LLM, and submit results automatically.
      </p>

      {!isConnected && (
        <div className="mb-6 p-4 bg-yellow-900/30 border border-yellow-700 rounded-lg text-sm text-yellow-300">
          Connect your wallet first.{' '}
          <ConnectButton />
        </div>
      )}

      <form onSubmit={handleDeploy} className="space-y-5">
        <div>
          <label className="block text-sm font-medium text-gray-300 mb-1">Agent name</label>
          <input
            required
            value={form.name}
            onChange={e => setForm(f => ({ ...f, name: e.target.value }))}
            placeholder="My Research Agent"
            className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-300 mb-1">System instructions</label>
          <textarea
            required
            rows={4}
            value={form.instructions}
            onChange={e => setForm(f => ({ ...f, instructions: e.target.value }))}
            placeholder="You are a research agent. When given a task, provide a concise, accurate response..."
            className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:ring-2 focus:ring-blue-500 resize-none"
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-300 mb-1">LLM provider</label>
          <div className="grid grid-cols-4 gap-2">
            {(Object.keys(PROVIDERS) as Provider[]).map(p => (
              <button
                key={p}
                type="button"
                onClick={() => setForm(f => ({ ...f, provider: p }))}
                className={`py-2 rounded-lg border text-sm font-medium transition-colors ${
                  form.provider === p
                    ? 'border-blue-500 bg-blue-900/40 text-blue-300'
                    : 'border-gray-700 text-gray-400 hover:border-gray-500'
                }`}
              >
                {PROVIDERS[p].label}
              </button>
            ))}
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-300 mb-1">Model</label>
          <select
            value={form.model}
            onChange={e => setForm(f => ({ ...f, model: e.target.value }))}
            className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            {PROVIDERS[form.provider].models.map(m => (
              <option key={m} value={m}>{m}</option>
            ))}
          </select>
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-300 mb-1">
            {PROVIDERS[form.provider].label} API key
          </label>
          <input
            required
            type="password"
            value={form.apiKey}
            onChange={e => setForm(f => ({ ...f, apiKey: e.target.value }))}
            placeholder="sk-..."
            className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white font-mono focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
          <p className="text-xs text-gray-500 mt-1">Stored server-side only.</p>
        </div>

        {error && <p className="text-sm text-red-400">{error}</p>}

        <button
          type="submit"
          disabled={loading || !isConnected}
          className="w-full bg-blue-600 hover:bg-blue-700 disabled:opacity-50 text-white font-medium py-2.5 rounded-lg text-sm transition-colors"
        >
          {loading ? 'Deploying…' : isConnected ? 'Deploy agent' : 'Connect wallet to deploy'}
        </button>
      </form>
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAccount } from 'wagmi';

type AgentStatus = 'stopped' | 'running' | 'paused';

interface DeployedAgent {
  id: string;
  ownerAddress: string;
  name: string;
  provider: string;
  model: string;
  capabilities: string[];
  status: AgentStatus;
  deployedAt: string;
}

const STATUS_STYLES: Record<AgentStatus, string> = {
  running: 'bg-green-900/40 text-green-400',
  paused:  'bg-yellow-900/40 text-yellow-400',
  stopped: 'bg-gray-800 text-gray-500',
};

export default function AgentMarketplace() {
  const { address } = useAccount();
  const navigate = useNavigate();
  const [agents, setAgents] = useState<DeployedAgent[]>([]);
  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState<string | null>(null);

  const fetchAgents = useCallback(async () => {
    try {
      const res = await fetch('/api/v1/agents');
      const json = await res.json();
      if (json.success) setAgents(json.data);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchAgents(); }, [fetchAgents]);

  async function action(id: string, verb: 'start' | 'pause' | 'stop') {
    setActionLoading(`${id}:${verb}`);
    try {
      const res = await fetch(`/api/v1/agents/${id}/${verb}`, { method: 'POST' });
      const json = await res.json();
      if (json.success) setAgents(prev => prev.map(a => a.id === id ? json.data : a));
    } finally {
      setActionLoading(null);
    }
  }

  return (
    <div className="max-w-5xl mx-auto px-4 py-10">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-2xl font-bold text-white">Agent Marketplace</h1>
          <p className="text-gray-400 text-sm mt-1">All deployed agents on the network</p>
        </div>
        <button
          onClick={() => navigate('/agents/deploy')}
          className="bg-blue-600 hover:bg-blue-700 text-white text-sm font-medium px-4 py-2 rounded-lg transition-colors"
        >
          + Deploy agent
        </button>
      </div>

      {loading ? (
        <div className="text-center py-20 text-gray-500">Loading agents…</div>
      ) : agents.length === 0 ? (
        <div className="text-center py-20">
          <p className="text-gray-500 mb-4">No agents deployed yet.</p>
          <button onClick={() => navigate('/agents/deploy')} className="text-blue-400 underline text-sm">
            Deploy the first one
          </button>
        </div>
      ) : (
        <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
          {agents.map(agent => {
            const isOwner = address?.toLowerCase() === agent.ownerAddress?.toLowerCase();
            const busy = actionLoading?.startsWith(agent.id);
            return (
              <div
                key={agent.id}
                className="border border-gray-800 rounded-xl p-5 bg-gray-950 cursor-pointer hover:border-gray-600 hover:bg-gray-900 transition-all group"
                onClick={() => navigate(`/agents/${agent.id}`)}
              >
                <div className="flex items-start justify-between mb-4">
                  <div className="flex items-center gap-3">
                    <div className="w-9 h-9 rounded-lg bg-blue-900/40 border border-blue-800/50 flex items-center justify-center text-blue-400 font-bold text-sm">
                      {agent.name.slice(0, 2).toUpperCase()}
                    </div>
                    <div>
                      <h3 className="font-semibold text-white text-sm">{agent.name}</h3>
                      <p className="text-xs text-gray-500 mt-0.5">{agent.provider} · {agent.model}</p>
                    </div>
                  </div>
                  <span className={`text-xs font-medium px-2 py-0.5 rounded-full flex items-center gap-1 ${STATUS_STYLES[agent.status]}`}>
                    <span className={`w-1.5 h-1.5 rounded-full ${
                      agent.status === 'running' ? 'bg-green-400 animate-pulse' :
                      agent.status === 'paused' ? 'bg-yellow-400' : 'bg-gray-500'
                    }`} />
                    {agent.status}
                  </span>
                </div>

                <p className="text-xs text-gray-600 mb-4">
                  Deployed {new Date(agent.deployedAt).toLocaleDateString()}
                </p>

                {isOwner && (
                  <div className="flex gap-2" onClick={e => e.stopPropagation()}>
                    {agent.status !== 'running' && (
                      <button
                        disabled={!!busy}
                        onClick={() => action(agent.id, 'start')}
                        className="flex-1 text-xs font-medium py-1.5 rounded-lg bg-green-900/30 text-green-400 hover:bg-green-900/50 disabled:opacity-50 transition-colors"
                      >
                        {actionLoading === `${agent.id}:start` ? '…' : '▶ Start'}
                      </button>
                    )}
                    {agent.status === 'running' && (
                      <button
                        disabled={!!busy}
                        onClick={() => action(agent.id, 'pause')}
                        className="flex-1 text-xs font-medium py-1.5 rounded-lg bg-yellow-900/30 text-yellow-400 hover:bg-yellow-900/50 disabled:opacity-50 transition-colors"
                      >
                        {actionLoading === `${agent.id}:pause` ? '…' : '⏸ Pause'}
                      </button>
                    )}
                    {agent.status !== 'stopped' && (
                      <button
                        disabled={!!busy}
                        onClick={() => action(agent.id, 'stop')}
                        className="flex-1 text-xs font-medium py-1.5 rounded-lg bg-red-900/30 text-red-400 hover:bg-red-900/50 disabled:opacity-50 transition-colors"
                      >
                        {actionLoading === `${agent.id}:stop` ? '…' : '⏹ Stop'}
                      </button>
                    )}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

